-- 배치종료일자 업데이트
UPDATE JRBA_RPT_BAS_M SET BT_JOB_ENDT = #{today}
WHERE RPT_GJDT = #{rptGjdt}

mapper.insert:
-- I.1.03.01 개인 고객 규모 INSERT INTO JRBA_JIPYO_MM_I (BAS_YYMM,JIPYO_IDX,IN_V,DR_DT,DR_TIME,SMMT_STRT_DT,SMMT_END_DT) SELECT SUBSTR(#{J1_E_DT},1,6) AS BAS_YYMM -- 기준년월 ,'I.1.03.01' AS JIPYO_IDX -- 보고지표인덱스 ,( SELECT SUM(RSLT_VALU) FROM ( SELECT COUNT(DISTINCT A.CDD_TAGT_ENTY_ID) AS RSLT_VALU FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A , SID.IDO_A_MAC_CLNT_ADDN_IFMN C , SID.IDO_A_MAC_CLNT_RGSN_DTLS D WHERE 1 = 1 AND A.CDD_TAGT_ENTY_ID = C.CLNT_ENTY_ID AND A.CDD_TAGT_ENTY_ID = D.CLNT_ENTY_ID
AND EXISTS (SELECT 1 FROM SID.IDO_A_UUA_ACNT B WHERE 1 = 1 AND (B.ACNT_STAS_TYPE_CODE IN ('AC', 'IN') -- 정상/통합계좌만 OR (B.ACNT_STAS_TYPE_CODE = 'CL' AND B.CLSG_DATE > #{btBasDt})) AND B.ACNT_TYPE_CODE IN ('GNAC', 'FPAC', 'FOAC', 'SVAC') -- 리테일계좌만 AND A.CDD_TAGT_ENTY_ID = B.ACNT_OWNR_ID ) AND NOT EXISTS (SELECT 1 FROM SID.IDO_A_MAH_CDD_FLFL_DTLD B WHERE B.CDD_TAGT_ENTY_ID = A.CDD_TAGT_ENTY_ID AND B.RGBR_CODE = '21220' /* 연금전략팀 */ AND B.CRFL_FLTG_RSLT_CODE NOT IN ('1','2','3') /* 요주의필터링결과코드 */ ) AND D.PRCE_DATE <= #{btBasDt} -- 고객등록일자 AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') -- 등급 존재 AND A.CDD_CLNT_SECT_CODE = '1' -- CDD고객구분코드(1.개인, 2.영리법인, 3.비영리법인)
) WHERE 1 = 1 ) AS IN_V ,TO_CHAR(SYSDATE,'YYYYMMDD') AS DR_DT -- 등록일자 ,TO_CHAR(SYSDATE,'HH24MISS') AS DR_TIME -- 등록시간 ,#{J1_S_DT} AS SMMT_STRT_DT -- 집계기준시작일 ,#{J1_E_DT} AS SMMT_END_DT -- 집계기준종료일 FROM DUAL

-- I.1.04.02 고액자산가 거래금액 규모 하반기 또는 상반기 INSERT INTO JRBA_JIPYO_MM_I (BAS_YYMM,JIPYO_IDX,IN_V,DR_DT,DR_TIME,SMMT_STRT_DT,SMMT_END_DT) SELECT SUBSTR(#{J1_E_DT},1,6) AS BAS_YYMM -- 기준년월 ,'I.1.04.02' AS JIPYO_IDX -- 보고지표인덱스 ,(SELECT ROUND(SUM(NULLIF(TRDG_AMNT,0)) / 1000000,2) --10774730.894992 FROM (
SELECT /*+ FULL(T) PARALLEL(T 8) */ SUM(CASE WHEN SUBSTR(T.TRDG_CODE, 1, 1) IN ('3', '4') THEN T.BFTX_KRW_TRDG_AMNT ELSE T.TRDG_DNOM_AMNT END) AS TRDG_AMNT FROM SID.IDO_A_MBA_TRDG T INNER JOIN SID.IDO_A_UWB_TRD_CD TC ON TC.TRDG_CODE = T.TRDG_CODE AND TC.DTLS_TRDG_NAME NOT LIKE '%대차%' WHERE T.TRDG_DATE BETWEEN #{J1_S_DT} AND #{J1_E_DT} AND T.TRDG_CODE >= '300000' AND T.TRDG_CODE NOT LIKE '%9' AND T.CANC_YN <> 'Y' AND T.CRNY_CODE IN ('KRW', ' ', '') AND T.TRDG_CODE NOT IN('301180' ,'301189' ,'301420' ,'301430' ,'301439' ,'301440' ,'301449' ,'301450' ,'301459' ,'301460','301469' ,'301890' ,'301899' ,'301900' ,'301909' ,'301910' ,'301919' ,'301920' ,'301929' ,'302230' ,'302239','302240' ,'302249' ,'303910' ,'303919' ,'A99010' ,'Q00400' ,'Q00800' ,'T00030' ,'U00080' ,'U00200' ,'U00500') AND T.ACNT_TRDG_KIND_CODE <> '14' -- 주석거래(관리점변경, 통장기장 등) AND T.PRCE_CHNL_SECT_CODE NOT LIKE 'B%' -- 배치거래 제외 AND T.ACNT_ID IN ( SELECT /*+ FULL(E) PARALLEL(E 8) */ B.ACNT_ID AS ACNT_ID FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A , SID.IDO_A_MAC_CLNT_ADDN_IFMN C , SID.IDO_A_MAC_CLNT_RGSN_DTLS D , ( SELECT CLNT_ENTY_ID, SUM(ASST_VLTN_ACML_AMNT)/(SELECT TO_NUMBER(TO_CHAR(LAST_DAY(TO_DATE(#{btBasDt, jdbcType=VARCHAR},'YYYYMMDD')), 'DD')) FROM DUAL) AS ASST_VLTN_ACML_AMNT FROM SID.IDA_SETL_STD_BAL_M A WHERE STNR_YYMM = #{YYYYMM} GROUP BY CLNT_ENTY_ID ) E , SID.IDO_A_UUA_ACNT B WHERE 1 = 1 AND A.CDD_TAGT_ENTY_ID = C.CLNT_ENTY_ID AND A.CDD_TAGT_ENTY_ID = D.CLNT_ENTY_ID AND A.CDD_TAGT_ENTY_ID = E.CLNT_ENTY_ID AND A.CDD_TAGT_ENTY_ID = B.ACNT_OWNR_ID AND (B.ACNT_STAS_TYPE_CODE IN ('AC', 'IN') -- 정상/통합계좌만 OR (B.ACNT_STAS_TYPE_CODE = 'CL' AND B.CLSG_DATE > #{btBasDt, jdbcType=VARCHAR})) AND B.ACNT_TYPE_CODE IN ('GNAC', 'FPAC', 'FOAC', 'SVAC') -- 리테일계좌만 AND ((A.RGBR_CODE <> '21220' OR A.CRFL_FLTG_RSLT_CODE IN ('1','2','3')) OR (A.RGBR_CODE <> '21220' AND A.CRFL_FLTG_RSLT_CODE IN ('1','2','3')) ) AND D.PRCE_DATE <= #{btBasDt, jdbcType=VARCHAR} -- 고객등록일자 AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.CDD_CLNT_SECT_CODE = '1' -- CDD고객구분코드(1.개인, 2.영리법인, 3.비영리법인) AND E.ASST_VLTN_ACML_AMNT >= 1000000000 -- 10억 )
UNION ALL
SELECT /*+ FULL(B) PARALLEL(B 8) */ SUM(CASE WHEN SUBSTR(T.TRDG_CODE, 1, 1) IN ('3', '4') THEN T.BFTX_FRGN_CRNY_TRDG_AMNT * (A.DATA_VALU / B.BAS_SCLG_FCTR) ELSE T.TRDG_DLNG_UNIT_PRIC * T.TRDG_PRCE_QNTY * (A.DATA_VALU / B.BAS_SCLG_FCTR) END) AS TRDG_AMNT FROM SID.IDO_A_MBA_TRDG T INNER JOIN SID.IDO_A_UWB_TRD_CD TC ON TC.TRDG_CODE = T.TRDG_CODE AND TC.DTLS_TRDG_NAME NOT LIKE '%대차%' INNER JOIN SID.IDO_A_UUM_MARKET_DATA A ON A.BSNS_DATE = T.TRDG_DATE AND A.PRIC_TYPE_CODE = 'BKR' -- 가격유형코드(BKR.한국은행고시환율) AND A.DATA_VALU_TYPE_CODE = 'XCR' -- 데이터값유형코드(XCR.환율) AND A.DATA_SORC_ENTY_ID = 102001 -- 블룸버그 AND A.EOD_TYPE_CODE = 'SNP' -- EOD유형코드(EOD.EOD, SNP.스냅샷) INNER JOIN SID.IDO_A_UUP_CURRENCY_PAIR B ON A.PRDT_ID = B.PRDT_ID AND B.BAS_CRNY_CODE = 'KRW' AND B.TAGT_CRNY_CODE = T.CRNY_CODE WHERE T.TRDG_DATE BETWEEN #{J1_S_DT} AND #{J1_E_DT} AND T.TRDG_CODE >= '300000' AND T.TRDG_CODE NOT LIKE '%9' AND T.CANC_YN <> 'Y' AND (T.CRNY_CODE <> 'KRW' AND T.CRNY_CODE <> ' ' AND T.CRNY_CODE IS NOT NULL) AND T.TRDG_CODE NOT IN('301180' ,'301189' ,'301420' ,'301430' ,'301439' ,'301440' ,'301449' ,'301450' ,'301459' ,'301460','301469' ,'301890' ,'301899' ,'301900' ,'301909' ,'301910' ,'301919' ,'301920' ,'301929' ,'302230' ,'302239','302240' ,'302249' ,'303910' ,'303919' ,'A99010' ,'Q00400' ,'Q00800' ,'T00030' ,'U00080' ,'U00200' ,'U00500') AND T.ACNT_TRDG_KIND_CODE <> '14' -- 주석거래(관리점변경, 통장기장 등) AND T.PRCE_CHNL_SECT_CODE NOT LIKE 'B%' -- 배치거래 제외 AND T.ACNT_ID IN ( SELECT /*+ FULL(E) PARALLEL(E 8) */ B.ACNT_ID AS ACNT_ID FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A , SID.IDO_A_MAC_CLNT_ADDN_IFMN C , SID.IDO_A_MAC_CLNT_RGSN_DTLS D , ( SELECT CLNT_ENTY_ID, SUM(ASST_VLTN_ACML_AMNT)/(SELECT TO_NUMBER(TO_CHAR(LAST_DAY(TO_DATE(#{btBasDt, jdbcType=VARCHAR},'YYYYMMDD')), 'DD')) FROM DUAL) AS ASST_VLTN_ACML_AMNT FROM SID.IDA_SETL_STD_BAL_M A WHERE STNR_YYMM = #{YYYYMM} GROUP BY CLNT_ENTY_ID ) E , SID.IDO_A_UUA_ACNT B WHERE 1 = 1 AND A.CDD_TAGT_ENTY_ID = C.CLNT_ENTY_ID AND A.CDD_TAGT_ENTY_ID = D.CLNT_ENTY_ID AND A.CDD_TAGT_ENTY_ID = E.CLNT_ENTY_ID AND A.CDD_TAGT_ENTY_ID = B.ACNT_OWNR_ID AND (B.ACNT_STAS_TYPE_CODE IN ('AC', 'IN') -- 정상/통합계좌만 OR (B.ACNT_STAS_TYPE_CODE = 'CL' AND B.CLSG_DATE > #{btBasDt, jdbcType=VARCHAR})) AND B.ACNT_TYPE_CODE IN ('GNAC', 'FPAC', 'FOAC', 'SVAC') -- 리테일계좌만 AND ((A.RGBR_CODE <> '21220' OR A.CRFL_FLTG_RSLT_CODE IN ('1','2','3')) OR (A.RGBR_CODE <> '21220' AND A.CRFL_FLTG_RSLT_CODE IN ('1','2','3')) ) AND D.PRCE_DATE <= #{btBasDt, jdbcType=VARCHAR} -- 고객등록일자 AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.CDD_CLNT_SECT_CODE = '1' -- CDD고객구분코드(1.개인, 2.영리법인, 3.비영리법인) AND E.ASST_VLTN_ACML_AMNT >= 1000000000 -- 10억 )
)
) AS IN_V ,TO_CHAR(SYSDATE,'YYYYMMDD') AS DR_DT -- 등록일자 ,TO_CHAR(SYSDATE,'HH24MISS') AS DR_TIME -- 등록시간 ,#{J1_S_DT} AS SMMT_STRT_DT -- 집계기준시작일 ,#{J1_E_DT} AS SMMT_END_DT -- 집계기준종료일 FROM DUAL

-- I.1.10.01 : 신규고객 중 고위험 규모 -- [산출식] 신규 고위험고객 비율 = (EDD 수행 신규고객 수) ÷ (신규고객 수) × 100 INSERT INTO JRBA_JIPYO_MM_I (BAS_YYMM,JIPYO_IDX,IN_V,DR_DT,DR_TIME,SMMT_STRT_DT,SMMT_END_DT) SELECT SUBSTR(#{J1_E_DT},1,6) AS BAS_YYMM -- 기준년월 ,'I.1.10.01' AS JIPYO_IDX -- 보고지표인덱스 ,( SELECT NVL(ROUND(NULLIF(XX.CNT_H,0) / NULLIF(ZZ.CNT_TOTAL * 100, 2),0),0) AS RSLT_VALU -- divisor is equal to zero 발생하여 수정 FROM ( SELECT COUNT(*) AS CNT_TOTAL FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A INNER JOIN SID.IDO_A_MAC_CLNT_RGSN_DTLS D -- 고객등록일자 확인용 ON D.CLNT_ENTY_ID = A.CDD_TAGT_ENTY_ID AND D.PRCE_DATE BETWEEN #{J1_S_DT} AND #{J1_E_DT} WHERE A.CDD_FLFL_DATE BETWEEN #{J1_S_DT} AND #{J1_E_DT} AND A.CDD_CMPL_YN = 'Y'
) ZZ , ( SELECT COUNT(*) AS CNT_H FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A INNER JOIN SID.IDO_A_MAC_CLNT_RGSN_DTLS D -- 고객등록일자 확인용 ON D.CLNT_ENTY_ID = A.CDD_TAGT_ENTY_ID AND D.PRCE_DATE BETWEEN #{J1_S_DT} AND #{J1_E_DT} WHERE A.CDD_FLFL_DATE BETWEEN #{J1_S_DT} AND #{J1_E_DT} AND A.CDD_CMPL_YN = 'Y' --AND A.CLNT_RISK_RTNG_CODE = 'H' AND A.EDD_TAGT_YN = 'Y' ) XX
) IN_V ,TO_CHAR(SYSDATE,'YYYYMMDD') AS DR_DT -- 등록일자 ,TO_CHAR(SYSDATE,'HH24MISS') AS DR_TIME -- 등록시간 ,#{J1_S_DT} AS SMMT_STRT_DT -- 집계기준시작일 ,#{J1_E_DT} AS SMMT_END_DT -- 집계기준종료일 FROM DUAL

INSERT INTO JRBA_JIPYO_MM_I (BAS_YYMM,JIPYO_IDX,IN_V,DR_DT,DR_TIME,SMMT_STRT_DT,SMMT_END_DT)
SELECT SUBSTR(#{J1_E_DT},1,6) AS BAS_YYMM -- 기준년월 ,'O.13.01.031' AS JIPYO_IDX -- 보고지표인덱스 ,( SELECT ROUND(L.CNT + M.CNT + H.CNT) FROM ( WITH TEMP_L AS (SELECT A.CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO , A.CDD_FLFL_DATE , A.CLNT_RISK_RTNG_CODE FROM SID.IDO_A_MAH_CDD_FLFL_CHAN A WHERE 1 = 1 AND EXISTS (SELECT 1 FROM SID.IDO_A_UUA_ACNT B WHERE 1 = 1 AND B.ACNT_TYPE_CODE IN ('GNAC', 'FPAC', 'FOAC', 'SVAC') /* 리테일계좌만 */ AND A.CDD_TAGT_ENTY_ID = B.ACNT_OWNR_ID AND (B.ACNT_STAS_TYPE_CODE IN ('AC', 'IN') /* 정상/통합계좌 보유고객 */ OR (B.ACNT_STAS_TYPE_CODE = 'CL' AND B.CLSG_DATE > #{btBasDt, jdbcType=VARCHAR})) ) AND (A.RGBR_CODE <> '21220' OR A.CRFL_FLTG_RSLT_CODE IN ('1','2','3')) AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.CDD_TAGT_ENTY_ID IN ( SELECT /*+ FULL(T) PARALLEL(T 8) */ U.ACNT_OWNR_ID FROM SID.IDO_A_MBA_TRDG T , SID.IDO_A_UUA_ACNT U WHERE T.ACNT_ID = U.ACNT_ID AND T.TRDG_DATE BETWEEN #{J1_S_DT} AND #{J1_E_DT} AND T.TRDG_CODE NOT IN ('301180' ,'301189' ,'301420' ,'301430' ,'301439' ,'301440' ,'301449' ,'301450' ,'301459' ,'301460' ,'301469' ,'301890' ,'301899' ,'301900' ,'301909' ,'301910' ,'301919' ,'301920' ,'301929' ,'302230' ,'302239' ,'302240' ,'302249' ,'303910' ,'303919' ,'A99010' ,'Q00400' ,'Q00800' ,'T00030' ,'U00080' ,'U00200' ,'U00500') ) AND A.CDD_CLNT_SECT_CODE = '1' -- CDD고객구분코드(1.개인, 2.영리법인, 3.비영리법인)
)
/* L 분모 대상 고객 중 20160421~20170420 기간 내 최초수행등급이 L이고, 20160421 ~ 20200420에 CDD를 2회 이상 한 고객(날짜가 다른 경우만) */ SELECT COUNT(DISTINCT M.CDD_TAGT_ENTY_ID) AS CNT
FROM TEMP_L M WHERE 1 = 1 /* 20160421 ~ 20170420 기간 내 최초수행등급이 L이고 */ AND EXISTS (SELECT 1 FROM TEMP_L P , ( SELECT L.CDD_TAGT_ENTY_ID , L.CDD_FLFL_DATE , L.CDD_FLFL_SQNO , L.RK FROM ( SELECT K.CDD_TAGT_ENTY_ID , K.CDD_FLFL_DATE , K.CDD_FLFL_SQNO , RANK() OVER (PARTITION BY K.CDD_TAGT_ENTY_ID ORDER BY K.CDD_FLFL_DATE ASC) AS RK FROM ( SELECT J.CDD_TAGT_ENTY_ID CDD_TAGT_ENTY_ID , J.CDD_FLFL_DATE CDD_FLFL_DATE , MAX(J.CDD_FLFL_SQNO) CDD_FLFL_SQNO FROM TEMP_L J WHERE 1 = 1 AND J.CDD_FLFL_DATE BETWEEN TO_CHAR(ADD_MONTHS(TO_DATE(#{J1_S_DT}, 'YYYYMMDD'), -36), 'YYYYMMDD') AND TO_CHAR(ADD_MONTHS(TO_DATE(#{J1_E_DT}, 'YYYYMMDD'), -36), 'YYYYMMDD')
GROUP BY J.CDD_TAGT_ENTY_ID, J.CDD_FLFL_DATE ) K WHERE 1 = 1 ) L WHERE 1 = 1 AND L.RK = 1 ) Q WHERE P.CDD_TAGT_ENTY_ID = Q.CDD_TAGT_ENTY_ID AND P.CDD_FLFL_SQNO = Q.CDD_FLFL_SQNO AND P.CLNT_RISK_RTNG_CODE = 'L'
AND P.CDD_TAGT_ENTY_ID = M.CDD_TAGT_ENTY_ID AND P.CDD_FLFL_SQNO = M.CDD_FLFL_SQNO )
/* 20160421 ~ 20200420에 CDD를 2회 이상 한 고객(날짜가 다른 경우만) */ AND EXISTS (SELECT 1 FROM ( SELECT DISTINCT Q.CDD_TAGT_ENTY_ID AS CDD_TAGT_ENTY_ID FROM ( SELECT DISTINCT P.CDD_TAGT_ENTY_ID , P.CDD_FLFL_DATE FROM TEMP_L P WHERE 1 = 1 AND P.CDD_FLFL_DATE BETWEEN TO_CHAR(ADD_MONTHS(TO_DATE(#{J1_S_DT}, 'YYYYMMDD'), -36), 'YYYYMMDD') AND #{J1_E_DT} GROUP BY P.CDD_TAGT_ENTY_ID, P.CDD_FLFL_DATE ) Q WHERE 1 = 1 GROUP BY Q.CDD_TAGT_ENTY_ID HAVING COUNT(*) > 1 ) R WHERE R.CDD_TAGT_ENTY_ID = M.CDD_TAGT_ENTY_ID )
) L , (
WITH TEMP_M AS ( SELECT A.CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO , A.CDD_FLFL_DATE , A.CLNT_RISK_RTNG_CODE FROM SID.IDO_A_MAH_CDD_FLFL_CHAN A WHERE 1 = 1 AND EXISTS (SELECT 1 FROM SID.IDO_A_UUA_ACNT B WHERE 1 = 1 AND B.ACNT_TYPE_CODE IN ('GNAC', 'FPAC', 'FOAC', 'SVAC') /* 리테일계좌만 */ AND A.CDD_TAGT_ENTY_ID = B.ACNT_OWNR_ID AND (B.ACNT_STAS_TYPE_CODE IN ('AC', 'IN') /* 정상/통합계좌 보유고객 */ OR (B.ACNT_STAS_TYPE_CODE = 'CL' AND B.CLSG_DATE > #{btBasDt, jdbcType=VARCHAR})) ) AND (A.RGBR_CODE <> '21220' OR A.CRFL_FLTG_RSLT_CODE IN ('1','2','3')) AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.CDD_TAGT_ENTY_ID IN ( SELECT /*+ FULL(T) PARALLEL(T 8) */ U.ACNT_OWNR_ID FROM SID.IDO_A_MBA_TRDG T , SID.IDO_A_UUA_ACNT U WHERE T.ACNT_ID = U.ACNT_ID AND T.TRDG_DATE BETWEEN #{J1_S_DT} AND #{J1_E_DT} AND T.TRDG_CODE NOT IN ('301180' ,'301189' ,'301420' ,'301430' ,'301439' ,'301440' ,'301449' ,'301450' ,'301459' ,'301460' ,'301469' ,'301890' ,'301899' ,'301900' ,'301909' ,'301910' ,'301919' ,'301920' ,'301929' ,'302230' ,'302239' ,'302240' ,'302249' ,'303910' ,'303919' ,'A99010' ,'Q00400' ,'Q00800' ,'T00030' ,'U00080' ,'U00200' ,'U00500') ) AND A.CDD_CLNT_SECT_CODE = '1' -- CDD고객구분코드(1.개인, 2.영리법인, 3.비영리법인)
)
/* M 분모 대상 고객 중 20170421~20180420 기간 내 최초수행등급이 M이고, 20170421 ~ 20200420에 CDD를 2회 이상 한 고객(날짜가 다른 경우만) */ SELECT COUNT(DISTINCT M.CDD_TAGT_ENTY_ID) AS CNT
FROM TEMP_M M WHERE 1 = 1 /* 20170421 ~ 20180420 기간 내 최초수행등급이 M이고 */ AND EXISTS (SELECT 1 FROM TEMP_M P , ( SELECT L.CDD_TAGT_ENTY_ID , L.CDD_FLFL_DATE , L.CDD_FLFL_SQNO , L.RK FROM ( SELECT K.CDD_TAGT_ENTY_ID , K.CDD_FLFL_DATE , K.CDD_FLFL_SQNO , RANK() OVER (PARTITION BY K.CDD_TAGT_ENTY_ID ORDER BY K.CDD_FLFL_DATE ASC) AS RK FROM ( SELECT J.CDD_TAGT_ENTY_ID CDD_TAGT_ENTY_ID , J.CDD_FLFL_DATE CDD_FLFL_DATE , MAX(J.CDD_FLFL_SQNO) CDD_FLFL_SQNO FROM TEMP_M J WHERE 1 = 1 AND J.CDD_FLFL_DATE BETWEEN TO_CHAR(ADD_MONTHS(TO_DATE(#{J1_S_DT}, 'YYYYMMDD'), -24), 'YYYYMMDD') AND TO_CHAR(ADD_MONTHS(TO_DATE(#{J1_E_DT}, 'YYYYMMDD'), -24), 'YYYYMMDD') GROUP BY J.CDD_TAGT_ENTY_ID, J.CDD_FLFL_DATE ) K WHERE 1 = 1 ) L WHERE 1 = 1 AND L.RK = 1 ) Q WHERE P.CDD_TAGT_ENTY_ID = Q.CDD_TAGT_ENTY_ID AND P.CDD_FLFL_SQNO = Q.CDD_FLFL_SQNO AND P.CLNT_RISK_RTNG_CODE = 'M'
AND P.CDD_TAGT_ENTY_ID = M.CDD_TAGT_ENTY_ID AND P.CDD_FLFL_SQNO = M.CDD_FLFL_SQNO )
/* 20170421 ~ 20200420에 CDD를 2회 이상 한 고객(날짜가 다른 경우만) */ AND EXISTS (SELECT 1 FROM ( SELECT DISTINCT Q.CDD_TAGT_ENTY_ID AS CDD_TAGT_ENTY_ID FROM ( SELECT DISTINCT P.CDD_TAGT_ENTY_ID , P.CDD_FLFL_DATE FROM TEMP_M P WHERE 1 = 1 AND P.CDD_FLFL_DATE BETWEEN #{J1_S_DT} AND #{J1_E_DT} GROUP BY P.CDD_TAGT_ENTY_ID, P.CDD_FLFL_DATE ) Q WHERE 1 = 1 GROUP BY Q.CDD_TAGT_ENTY_ID HAVING COUNT(*) > 1 ) R WHERE R.CDD_TAGT_ENTY_ID = M.CDD_TAGT_ENTY_ID )
) M
, (
WITH TEMP_H AS ( SELECT A.CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO , A.CDD_FLFL_DATE , A.CLNT_RISK_RTNG_CODE FROM SID.IDO_A_MAH_CDD_FLFL_CHAN A WHERE 1 = 1 AND EXISTS (SELECT 1 FROM SID.IDO_A_UUA_ACNT B WHERE 1 = 1 AND B.ACNT_TYPE_CODE IN ('GNAC', 'FPAC', 'FOAC', 'SVAC') /* 리테일계좌만 */ AND A.CDD_TAGT_ENTY_ID = B.ACNT_OWNR_ID AND (B.ACNT_STAS_TYPE_CODE IN ('AC', 'IN') /* 정상/통합계좌 보유고객 */ OR (B.ACNT_STAS_TYPE_CODE = 'CL' AND B.CLSG_DATE > #{btBasDt, jdbcType=VARCHAR})) ) AND (A.RGBR_CODE <> '21220' OR A.CRFL_FLTG_RSLT_CODE IN ('1','2','3')) AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.CDD_TAGT_ENTY_ID IN ( SELECT /*+ FULL(T) PARALLEL(T 8) */ U.ACNT_OWNR_ID FROM SID.IDO_A_MBA_TRDG T , SID.IDO_A_UUA_ACNT U WHERE T.ACNT_ID = U.ACNT_ID AND T.TRDG_DATE BETWEEN #{J1_S_DT} AND #{J1_E_DT} AND T.TRDG_CODE NOT IN ('301180' ,'301189' ,'301420' ,'301430' ,'301439' ,'301440' ,'301449' ,'301450' ,'301459' ,'301460' ,'301469' ,'301890' ,'301899' ,'301900' ,'301909' ,'301910' ,'301919' ,'301920' ,'301929' ,'302230' ,'302239' ,'302240' ,'302249' ,'303910' ,'303919' ,'A99010' ,'Q00400' ,'Q00800' ,'T00030' ,'U00080' ,'U00200' ,'U00500') ) AND A.CDD_CLNT_SECT_CODE = '1' -- CDD고객구분코드(1.개인, 2.영리법인, 3.비영리법인)
) /* H 분모 대상 고객 중 20180421~20190420 기간 내 최초수행등급이 H이고, 20180421 ~ 20200420에 CDD를 2회 이상 한 고객(날짜가 다른 경우만) */ SELECT COUNT(DISTINCT M.CDD_TAGT_ENTY_ID) AS CNT
FROM TEMP_H M WHERE 1 = 1 /* 20180421 ~ 20190420 기간 내 최초수행등급이 H이고 */ AND EXISTS (SELECT 1 FROM TEMP_H P , ( SELECT L.CDD_TAGT_ENTY_ID , L.CDD_FLFL_DATE , L.CDD_FLFL_SQNO , L.RK FROM ( SELECT K.CDD_TAGT_ENTY_ID , K.CDD_FLFL_DATE , K.CDD_FLFL_SQNO , RANK() OVER (PARTITION BY K.CDD_TAGT_ENTY_ID ORDER BY K.CDD_FLFL_DATE ASC) AS RK FROM ( SELECT J.CDD_TAGT_ENTY_ID CDD_TAGT_ENTY_ID , J.CDD_FLFL_DATE CDD_FLFL_DATE , MAX(J.CDD_FLFL_SQNO) CDD_FLFL_SQNO FROM TEMP_H J WHERE 1 = 1 AND J.CDD_FLFL_DATE BETWEEN TO_CHAR(ADD_MONTHS(TO_DATE(#{J1_S_DT}, 'YYYYMMDD'), -24), 'YYYYMMDD') AND TO_CHAR(ADD_MONTHS(TO_DATE(#{J1_E_DT}, 'YYYYMMDD'), -24), 'YYYYMMDD') GROUP BY J.CDD_TAGT_ENTY_ID, J.CDD_FLFL_DATE ) K WHERE 1 = 1 ) L WHERE 1 = 1 AND L.RK = 1 ) Q WHERE P.CDD_TAGT_ENTY_ID = Q.CDD_TAGT_ENTY_ID AND P.CDD_FLFL_SQNO = Q.CDD_FLFL_SQNO AND P.CLNT_RISK_RTNG_CODE = 'H'
AND P.CDD_TAGT_ENTY_ID = M.CDD_TAGT_ENTY_ID AND P.CDD_FLFL_SQNO = M.CDD_FLFL_SQNO )
/* 20180421 ~ 20200420에 CDD를 2회 이상 한 고객(날짜가 다른 경우만) */ AND EXISTS (SELECT 1 FROM ( SELECT DISTINCT Q.CDD_TAGT_ENTY_ID AS CDD_TAGT_ENTY_ID FROM ( SELECT DISTINCT P.CDD_TAGT_ENTY_ID , P.CDD_FLFL_DATE FROM TEMP_H P WHERE 1 = 1 AND P.CDD_FLFL_DATE BETWEEN TO_CHAR(ADD_MONTHS(TO_DATE( #{J1_S_DT}, 'YYYYMMDD'), -24), 'YYYYMMDD') AND #{J1_E_DT} GROUP BY P.CDD_TAGT_ENTY_ID, P.CDD_FLFL_DATE ) Q WHERE 1 = 1 GROUP BY Q.CDD_TAGT_ENTY_ID HAVING COUNT(*) > 1 ) R WHERE R.CDD_TAGT_ENTY_ID = M.CDD_TAGT_ENTY_ID )
) H ) AS IN_V ,TO_CHAR(SYSDATE,'YYYYMMDD') AS DR_DT -- 등록일자 ,TO_CHAR(SYSDATE,'HH24MISS') AS DR_TIME -- 등록시간 ,#{J1_S_DT} AS SMMT_STRT_DT -- 집계기준시작일 ,#{J1_E_DT} AS SMMT_END_DT -- 집계기준종료일 FROM DUAL

