SELECT SUBSTR(#{J1_E_DT},1,6) AS BAS_YYMM -- 기준년월 ,'O.13.01.092' AS JIPYO_IDX -- 보고지표인덱스 ,( SELECT ROUND(L.CNT + M.CNT + H.CNT) FROM ( WITH TEMP_L AS ( SELECT A.CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO , A.CDD_FLFL_DATE , A.CLNT_RISK_RTNG_CODE FROM SID.IDO_A_MAH_CDD_FLFL_CHAN A WHERE 1 = 1 AND EXISTS (SELECT 1 FROM SID.IDO_A_UUA_ACNT B WHERE 1 = 1 AND B.ACNT_TYPE_CODE IN ('GNAC', 'FPAC', 'FOAC', 'SVAC') /* 리테일계좌만 */ AND A.CDD_TAGT_ENTY_ID = B.ACNT_OWNR_ID AND (B.ACNT_STAS_TYPE_CODE IN ('AC', 'IN') /* 정상/통합계좌 보유고객 */ OR (B.ACNT_STAS_TYPE_CODE = 'CL' AND B.CLSG_DATE > #{btBasDt, jdbcType=VARCHAR})) ) AND ((A.RGBR_CODE <> '21220' OR A.CRFL_FLTG_RSLT_CODE IN ('1','2','3')) OR (A.RGBR_CODE <> '21220' AND A.CRFL_FLTG_RSLT_CODE IN ('1','2','3')) ) AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.CDD_TAGT_ENTY_ID IN ( SELECT /*+ FULL(T) PARALLEL(T 8) */ U.ACNT_OWNR_ID FROM SID.IDO_A_MBA_TRDG T , SID.IDO_A_UUA_ACNT U WHERE T.ACNT_ID = U.ACNT_ID AND T.TRDG_DATE BETWEEN #{J1_S_DT} AND #{J1_E_DT} AND T.TRDG_CODE NOT IN ('301180' ,'301189' ,'301420' ,'301430' ,'301439' ,'301440' ,'301449' ,'301450' ,'301459' ,'301460' ,'301469' ,'301890' ,'301899' ,'301900' ,'301909' ,'301910' ,'301919' ,'301920' ,'301929' ,'302230' ,'302239' ,'302240' ,'302249' ,'303910' ,'303919' ,'A99010' ,'Q00400' ,'Q00800' ,'T00030' ,'U00080' ,'U00200' ,'U00500') ) AND (A.NTNY_ID IN ( -- 사업장국가ID : CDD정보 SELECT CNTY_ID FROM SID.IDO_A_UUE_COUNTRY C1 , ( SELECT DISTINCT NTN_CD FROM SRBA_NAT_I WHERE BAS_YYMM IN ( SELECT MAX(BAS_YYMM) AS BAS_YYMM FROM SRBA_NAT_I ) ) C2 WHERE 1 = 1 AND TRIM(C1.CNTY_CODE) = TRIM(C2.NTN_CD) )
OR A.BSPL_CNTY_ID IN ( -- 사업장국가ID : CDD정보 SELECT CNTY_ID FROM SID.IDO_A_UUE_COUNTRY C1 , ( SELECT DISTINCT NTN_CD FROM SRBA_NAT_I WHERE BAS_YYMM IN ( SELECT MAX(BAS_YYMM) AS BAS_YYMM FROM SRBA_NAT_I ) ) C2 WHERE 1 = 1 AND TRIM(C1.CNTY_CODE) = TRIM(C2.NTN_CD) )
OR A.MNBR_CNTY_ID IN ( -- 본점국가ID : CDD정보 SELECT CNTY_ID FROM SID.IDO_A_UUE_COUNTRY C1 , ( SELECT DISTINCT NTN_CD FROM SRBA_NAT_I WHERE BAS_YYMM IN ( SELECT MAX(BAS_YYMM) AS BAS_YYMM FROM SRBA_NAT_I ) ) C2 WHERE 1 = 1 AND TRIM(C1.CNTY_CODE) = TRIM(C2.NTN_CD) ) ) )
/* L 분모 대상 고객 중 20160421~20170420 기간 내 최초수행등급이 L이고, 20160421 ~ 20200420에 CDD를 2회 이상 한 고객(날짜가 다른 경우만) */ SELECT COUNT(DISTINCT M.CDD_TAGT_ENTY_ID) AS CNT
FROM TEMP_L M WHERE 1 = 1 /* 20160421 ~ 20170420 기간 내 최초수행등급이 L이고 */ AND EXISTS (SELECT 1 FROM TEMP_L P , ( SELECT L.CDD_TAGT_ENTY_ID , L.CDD_FLFL_DATE , L.CDD_FLFL_SQNO , L.RK FROM ( SELECT K.CDD_TAGT_ENTY_ID , K.CDD_FLFL_DATE , K.CDD_FLFL_SQNO , RANK() OVER (PARTITION BY K.CDD_TAGT_ENTY_ID ORDER BY K.CDD_FLFL_DATE ASC) AS RK FROM ( SELECT J.CDD_TAGT_ENTY_ID CDD_TAGT_ENTY_ID , J.CDD_FLFL_DATE CDD_FLFL_DATE , MAX(J.CDD_FLFL_SQNO) CDD_FLFL_SQNO FROM TEMP_L J WHERE 1 = 1 AND J.CDD_FLFL_DATE BETWEEN TO_CHAR(ADD_MONTHS(TO_DATE(#{J1_S_DT}, 'YYYYMMDD'), -36), 'YYYYMMDD') AND TO_CHAR(ADD_MONTHS(TO_DATE(#{J1_E_DT}, 'YYYYMMDD'), -36), 'YYYYMMDD') GROUP BY J.CDD_TAGT_ENTY_ID, J.CDD_FLFL_DATE ) K WHERE 1 = 1 ) L WHERE 1 = 1 AND L.RK = 1 ) Q WHERE P.CDD_TAGT_ENTY_ID = Q.CDD_TAGT_ENTY_ID AND P.CDD_FLFL_SQNO = Q.CDD_FLFL_SQNO AND P.CLNT_RISK_RTNG_CODE = 'L'
AND P.CDD_TAGT_ENTY_ID = M.CDD_TAGT_ENTY_ID AND P.CDD_FLFL_SQNO = M.CDD_FLFL_SQNO )
/* 20160421 ~ 20200420에 CDD를 2회 이상 한 고객(날짜가 다른 경우만) */ AND EXISTS (SELECT 1 FROM ( SELECT DISTINCT Q.CDD_TAGT_ENTY_ID AS CDD_TAGT_ENTY_ID FROM ( SELECT DISTINCT P.CDD_TAGT_ENTY_ID , P.CDD_FLFL_DATE FROM TEMP_L P WHERE 1 = 1 AND P.CDD_FLFL_DATE BETWEEN TO_CHAR(ADD_MONTHS(TO_DATE(#{J1_S_DT}, 'YYYYMMDD'), -36), 'YYYYMMDD') AND TO_CHAR(ADD_MONTHS(TO_DATE(#{J1_E_DT}, 'YYYYMMDD'), -36), 'YYYYMMDD') GROUP BY P.CDD_TAGT_ENTY_ID, P.CDD_FLFL_DATE ) Q WHERE 1 = 1 GROUP BY Q.CDD_TAGT_ENTY_ID HAVING COUNT(*) > 1 ) R WHERE R.CDD_TAGT_ENTY_ID = M.CDD_TAGT_ENTY_ID )
) L , (
WITH TEMP_M AS ( SELECT A.CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO , A.CDD_FLFL_DATE , A.CLNT_RISK_RTNG_CODE FROM SID.IDO_A_MAH_CDD_FLFL_CHAN A WHERE 1 = 1 AND EXISTS (SELECT 1 FROM SID.IDO_A_UUA_ACNT B WHERE 1 = 1 AND B.ACNT_TYPE_CODE IN ('GNAC', 'FPAC', 'FOAC', 'SVAC') /* 리테일계좌만 */ AND A.CDD_TAGT_ENTY_ID = B.ACNT_OWNR_ID AND (B.ACNT_STAS_TYPE_CODE IN ('AC', 'IN') /* 정상/통합계좌 보유고객 */ OR (B.ACNT_STAS_TYPE_CODE = 'CL' AND B.CLSG_DATE > #{btBasDt, jdbcType=VARCHAR})) ) AND ((A.RGBR_CODE <> '21220' OR A.CRFL_FLTG_RSLT_CODE IN ('1','2','3')) OR (A.RGBR_CODE <> '21220' AND A.CRFL_FLTG_RSLT_CODE IN ('1','2','3')) ) AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.CDD_TAGT_ENTY_ID IN ( SELECT /*+ FULL(T) PARALLEL(T 8) */ U.ACNT_OWNR_ID FROM SID.IDO_A_MBA_TRDG T , SID.IDO_A_UUA_ACNT U WHERE T.ACNT_ID = U.ACNT_ID AND T.TRDG_DATE BETWEEN #{J1_S_DT} AND #{J1_E_DT} AND T.TRDG_CODE NOT IN ('301180' ,'301189' ,'301420' ,'301430' ,'301439' ,'301440' ,'301449' ,'301450' ,'301459' ,'301460' ,'301469' ,'301890' ,'301899' ,'301900' ,'301909' ,'301910' ,'301919' ,'301920' ,'301929' ,'302230' ,'302239' ,'302240' ,'302249' ,'303910' ,'303919' ,'A99010' ,'Q00400' ,'Q00800' ,'T00030' ,'U00080' ,'U00200' ,'U00500') ) AND (A.NTNY_ID IN ( -- 사업장국가ID : CDD정보 SELECT CNTY_ID FROM SID.IDO_A_UUE_COUNTRY C1 , ( SELECT DISTINCT NTN_CD FROM SRBA_NAT_I WHERE BAS_YYMM IN ( SELECT MAX(BAS_YYMM) AS BAS_YYMM FROM SRBA_NAT_I ) ) C2 WHERE 1 = 1 AND TRIM(C1.CNTY_CODE) = TRIM(C2.NTN_CD) )
OR A.BSPL_CNTY_ID IN ( -- 사업장국가ID : CDD정보 SELECT CNTY_ID FROM SID.IDO_A_UUE_COUNTRY C1 , ( SELECT DISTINCT NTN_CD FROM SRBA_NAT_I WHERE BAS_YYMM IN ( SELECT MAX(BAS_YYMM) AS BAS_YYMM FROM SRBA_NAT_I ) ) C2 WHERE 1 = 1 AND TRIM(C1.CNTY_CODE) = TRIM(C2.NTN_CD) )
OR A.MNBR_CNTY_ID IN ( -- 본점국가ID : CDD정보 SELECT CNTY_ID FROM SID.IDO_A_UUE_COUNTRY C1 , ( SELECT DISTINCT NTN_CD FROM SRBA_NAT_I WHERE BAS_YYMM IN ( SELECT MAX(BAS_YYMM) AS BAS_YYMM FROM SRBA_NAT_I ) ) C2 WHERE 1 = 1 AND TRIM(C1.CNTY_CODE) = TRIM(C2.NTN_CD) ) ) )
/* M 분모 대상 고객 중 20170421~20180420 기간 내 최초수행등급이 M이고, 20170421 ~ 20200420에 CDD를 2회 이상 한 고객(날짜가 다른 경우만) */ SELECT COUNT(DISTINCT M.CDD_TAGT_ENTY_ID) AS CNT
FROM TEMP_M M WHERE 1 = 1 /* 20170421 ~ 20180420 기간 내 최초수행등급이 M이고 */ AND EXISTS (SELECT 1 FROM TEMP_M P , ( SELECT L.CDD_TAGT_ENTY_ID , L.CDD_FLFL_DATE , L.CDD_FLFL_SQNO , L.RK FROM ( SELECT K.CDD_TAGT_ENTY_ID , K.CDD_FLFL_DATE , K.CDD_FLFL_SQNO , RANK() OVER (PARTITION BY K.CDD_TAGT_ENTY_ID ORDER BY K.CDD_FLFL_DATE ASC) AS RK FROM ( SELECT J.CDD_TAGT_ENTY_ID CDD_TAGT_ENTY_ID , J.CDD_FLFL_DATE CDD_FLFL_DATE , MAX(J.CDD_FLFL_SQNO) CDD_FLFL_SQNO FROM TEMP_M J WHERE 1 = 1 AND J.CDD_FLFL_DATE BETWEEN #{J1_S_DT} AND #{J1_E_DT} AND J.CDD_FLFL_DATE BETWEEN TO_CHAR(ADD_MONTHS(TO_DATE(#{J1_S_DT}, 'YYYYMMDD'), -12), 'YYYYMMDD') AND TO_CHAR(ADD_MONTHS(TO_DATE(#{J1_E_DT}, 'YYYYMMDD'), -12), 'YYYYMMDD') GROUP BY J.CDD_TAGT_ENTY_ID, J.CDD_FLFL_DATE ) K WHERE 1 = 1 ) L WHERE 1 = 1 AND L.RK = 1 ) Q WHERE P.CDD_TAGT_ENTY_ID = Q.CDD_TAGT_ENTY_ID AND P.CDD_FLFL_SQNO = Q.CDD_FLFL_SQNO AND P.CLNT_RISK_RTNG_CODE = 'M'
AND P.CDD_TAGT_ENTY_ID = M.CDD_TAGT_ENTY_ID AND P.CDD_FLFL_SQNO = M.CDD_FLFL_SQNO )
/* 20170421 ~ 20200420에 CDD를 2회 이상 한 고객(날짜가 다른 경우만) */ AND EXISTS (SELECT 1 FROM ( SELECT DISTINCT Q.CDD_TAGT_ENTY_ID AS CDD_TAGT_ENTY_ID FROM ( SELECT DISTINCT P.CDD_TAGT_ENTY_ID , P.CDD_FLFL_DATE FROM TEMP_M P WHERE 1 = 1 AND P.CDD_FLFL_DATE BETWEEN TO_CHAR(ADD_MONTHS(TO_DATE(#{J1_S_DT}, 'YYYYMMDD'), -12), 'YYYYMMDD') AND #{J1_E_DT} GROUP BY P.CDD_TAGT_ENTY_ID, P.CDD_FLFL_DATE ) Q WHERE 1 = 1 GROUP BY Q.CDD_TAGT_ENTY_ID HAVING COUNT(*) > 1 ) R WHERE R.CDD_TAGT_ENTY_ID = M.CDD_TAGT_ENTY_ID )
) M
