FROM TEMP_H M WHERE 1 = 1 /* 20180421 ~ 20190420 기간 내 최초수행등급이 H이고 */ AND EXISTS (SELECT 1 FROM TEMP_H P , ( SELECT L.CDD_TAGT_ENTY_ID , L.CDD_FLFL_DATE , L.CDD_FLFL_SQNO , L.RK FROM ( SELECT K.CDD_TAGT_ENTY_ID , K.CDD_FLFL_DATE , K.CDD_FLFL_SQNO , RANK() OVER (PARTITION BY K.CDD_TAGT_ENTY_ID ORDER BY K.CDD_FLFL_DATE ASC) AS RK FROM ( SELECT J.CDD_TAGT_ENTY_ID CDD_TAGT_ENTY_ID , J.CDD_FLFL_DATE CDD_FLFL_DATE , MAX(J.CDD_FLFL_SQNO) CDD_FLFL_SQNO FROM TEMP_H J WHERE 1 = 1 AND J.CDD_FLFL_DATE BETWEEN TO_CHAR(ADD_MONTHS(TO_DATE(#{J1_S_DT}, 'YYYYMMDD'), -12), 'YYYYMMDD') AND TO_CHAR(ADD_MONTHS(TO_DATE(#{J1_E_DT}, 'YYYYMMDD'), -12), 'YYYYMMDD') GROUP BY J.CDD_TAGT_ENTY_ID, J.CDD_FLFL_DATE ) K WHERE 1 = 1 ) L WHERE 1 = 1 AND L.RK = 1 ) Q WHERE P.CDD_TAGT_ENTY_ID = Q.CDD_TAGT_ENTY_ID AND P.CDD_FLFL_SQNO = Q.CDD_FLFL_SQNO AND P.CLNT_RISK_RTNG_CODE = 'H'
